'use client';
import { useAsidemenu } from '@/hooks/useAsideMenu';

export default function Asidemenu() {
  const { isOpen, setIsOpen } = useAsidemenu();
  console.log(isOpen);
  return (
    <aside>
      <button onClick={() => setIsOpen(!isOpen)}>
        {isOpen ? 'Close' : 'Open'}
      </button>
      {isOpen && <div>Asidemenu Content</div>}
    </aside>
  );
}
